/*
==================================================
Design System
Derived from provided palette and screenshot analysis
==================================================
*/

:root {
    /* Brand Colors */
    --color-primary-red: #D4371F;
    --color-primary-olive: #AEBB63;

    --color-secondary-olive: #8AA03C;
    --color-secondary-orange: #E78423;

    --color-accent-blue: #1E88E5;

    --color-neutral-0: #FFFFFF;
    --color-neutral-50: #F5F3EF; /* page background */
    --color-neutral-900: #333333;

    /* Semantic */
    --color-success: #8AA03C;
    --color-error: #D4371F;
    --color-warning: #E78423;
    --color-info: #1E88E5;

    /* Typography */
    --font-heading: 'Space Grotesk', Helvetica, sans-serif;
    --font-body: 'Source Sans 3', Arial, sans-serif;

    --font-size-h1: 2.4rem;   /* 38px */
    --font-size-h2: 2.0rem;   /* 32px */
    --font-size-h3: 1.375rem; /* 22px */
    --font-size-body: 1rem;   /* 16px */
    --font-size-small: 0.8125rem; /* 13px */

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.7;

    /* Spacing Scale (base unit 8px) */
    --space-2xs: 4px;
    --space-xs: 8px;
    --space-sm: 16px;
    --space-md: 24px;
    --space-lg: 32px;
    --space-xl: 48px;
    --space-2xl: 64px;

    /* Layout */
    --container-max-width: 1120px;
    --border-radius-card: 3px;
    --shadow-card: 0 10px 24px rgba(0, 0, 0, 0.09);
    --shadow-header: 0 2px 6px rgba(0, 0, 0, 0.08);
}

/*
==================================================
Global Reset / Base
==================================================
*/

*,
*::before,
*::after {
    box-sizing: border-box;
}

html {
    font-size: 100%;
    scroll-behavior: smooth;
}

body.site-body {
    margin: 0;
    min-height: 100vh;
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-relaxed);
    color: var(--color-neutral-900);
    background-color: var(--color-neutral-50);
    /* subtle mottled background to echo the design texture */
    background-image:
        radial-gradient(circle at 0 0, rgba(0, 0, 0, 0.03) 0, transparent 60%),
        radial-gradient(circle at 100% 100%, rgba(0, 0, 0, 0.035) 0, transparent 55%);
}

img {
    max-width: 100%;
    display: block;
}

a {
    color: inherit;
    text-decoration: none;
}

a:focus-visible,
button:focus-visible,
[role="button"]:focus-visible {
    outline: 2px solid var(--color-accent-blue);
    outline-offset: 2px;
}

.site-main {
    display: block;
    padding: var(--space-xl) var(--space-sm) var(--space-2xl);
}

.container {
    max-width: var(--container-max-width);
    margin-inline: auto;
    padding-inline: var(--space-sm);
}

/*
==================================================
Typography
==================================================
*/

h1,
h2,
h3,
h4,
h5,
h6 {
    margin: 0 0 var(--space-sm);
    font-family: var(--font-heading);
    font-weight: 700;
    line-height: var(--line-height-tight);
    text-transform: uppercase;
    letter-spacing: 0.08em;
}

h1 {
    font-size: var(--font-size-h1);
}

h2 {
    font-size: var(--font-size-h2);
}

h3 {
    font-size: var(--font-size-h3);
}

p {
    margin: 0 0 var(--space-sm);
}

strong {
    font-weight: 700;
}

.small-text {
    font-size: var(--font-size-small);
}

.text-highlight-orange {
    color: var(--color-secondary-orange);
    font-weight: 700;
}

/*
==================================================
Header / Primary Navigation
==================================================
*/

.site-header {
    position: sticky;
    top: 0;
    z-index: 20;
    background-color: var(--color-neutral-0);
    box-shadow: var(--shadow-header);
}

.header-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-block: var(--space-sm);
}

.site-logo {
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.site-logo__title {
    font-family: var(--font-heading);
    font-size: 1.25rem;
    font-weight: 700;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: var(--color-primary-red);
}

.site-logo__tagline {
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.18em;
    color: var(--color-secondary-olive);
}

.site-nav {
    font-family: var(--font-body);
    font-size: 0.95rem;
}

.nav-list {
    display: flex;
    align-items: center;
    gap: var(--space-md);
    list-style: none;
    margin: 0;
    padding: 0;
}

.nav-link {
    position: relative;
    display: inline-block;
    padding-block: 4px;
    text-transform: uppercase;
    letter-spacing: 0.12em;
    font-weight: 600;
    color: var(--color-neutral-900);
    transition: color 0.18s ease, border-color 0.18s ease;
    border-bottom: 2px solid transparent;
}

.nav-link:hover {
    color: var(--color-primary-red);
    border-bottom-color: var(--color-secondary-olive);
}

.nav-link--current {
    color: var(--color-primary-red);
    border-bottom-color: var(--color-primary-red);
}

/* Stacking behavior on small screens without interactive hamburger */
@media (max-width: 960px) {
    .header-inner {
        flex-direction: column;
        align-items: flex-start;
        gap: var(--space-sm);
    }

    .nav-list {
        flex-wrap: wrap;
        row-gap: var(--space-xs);
        column-gap: var(--space-sm);
    }

    .nav-link {
        font-size: 0.85rem;
    }
}

/*
==================================================
Cards & Section Bands (for content inside #content)
==================================================
*/

.content-card {
    background-color: var(--color-neutral-0);
    box-shadow: var(--shadow-card);
    border-radius: var(--border-radius-card);
    padding: var(--space-lg) var(--space-xl);
}

@media (max-width: 768px) {
    .content-card {
        padding: var(--space-md) var(--space-md);
    }
}

.section-band {
    margin-top: var(--space-xl);
    padding: var(--space-lg) var(--space-sm);
    text-align: center;
    font-family: var(--font-heading);
    font-size: var(--font-size-h2);
    text-transform: uppercase;
    letter-spacing: 0.12em;
    font-weight: 700;
}

.section-band--olive {
    background-color: var(--color-primary-olive);
    color: var(--color-neutral-0);
}

.section-band--red {
    background-color: var(--color-primary-red);
    color: var(--color-neutral-0);
}

/*
==================================================
Chevron List Pattern (used inside cards)
==================================================
*/

.list-chevrons {
    list-style: none;
    margin: 0;
    padding: 0;
}

.list-chevrons > li {
    display: flex;
    align-items: flex-start;
    gap: var(--space-sm);
    padding-block: var(--space-xs);
}

.list-chevrons > li::before {
    content: '›';
    flex: 0 0 auto;
    margin-top: 1px;
    font-family: var(--font-heading);
    font-weight: 700;
    font-size: 1.1rem;
    color: var(--color-secondary-olive);
}

.list-chevrons p {
    margin: 0;
}

/*
==================================================
Footer
==================================================
*/

.site-footer {
    margin-top: var(--space-2xl);
    color: var(--color-neutral-0);
    background-color: #2E2E2E; /* slightly deeper than #333 for bottom weight */
}

.footer-top {
    background: linear-gradient(135deg, #363636 0%, #2E2E2E 45%, #2E2E2E 100%);
    padding-block: var(--space-xl);
}

.footer-inner {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-xl);
    align-items: flex-start;
}

.footer-brand {
    flex: 1 1 260px;
}

.footer-logo {
    font-family: var(--font-heading);
    font-size: 1.1rem;
    text-transform: uppercase;
    letter-spacing: 0.18em;
    font-weight: 700;
    margin-bottom: var(--space-xs);
    color: var(--color-primary-olive);
}

.footer-text {
    margin: 0;
    font-size: 0.95rem;
    line-height: var(--line-height-relaxed);
    color: #E6E2DC;
}

.footer-nav {
    flex: 2 1 320px;
}

.footer-links {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    gap: var(--space-xs) var(--space-md);
}

.footer-link {
    font-size: 0.9rem;
    color: #F5F3EF;
    text-transform: uppercase;
    letter-spacing: 0.12em;
    font-weight: 500;
    padding-block: 2px;
    border-bottom: 1px solid transparent;
    transition: color 0.18s ease, border-color 0.18s ease;
}

.footer-link:hover {
    color: var(--color-secondary-orange);
    border-bottom-color: var(--color-secondary-orange);
}

.footer-bottom {
    border-top: 1px solid rgba(255, 255, 255, 0.06);
    background-color: #262626;
}

.footer-bottom-inner {
    padding-block: var(--space-sm);
    text-align: center;
}

.footer-copy {
    margin: 0;
    font-size: 0.8rem;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    color: #C9C5BD;
}

@media (max-width: 768px) {
    .site-main {
        padding-inline: var(--space-xs);
    }

    .footer-inner {
        flex-direction: column;
        gap: var(--space-lg);
    }
}

/*
==================================================
Utility Classes
==================================================
*/

.section-spacing {
    margin-block: var(--space-xl);
}

.align-center {
    text-align: center;
}

.text-red {
    color: var(--color-primary-red);
}

.text-olive {
    color: var(--color-secondary-olive);
}

.bg-white {
    background-color: var(--color-neutral-0);
}

.bg-olive {
    background-color: var(--color-primary-olive);
}

.bg-red {
    background-color: var(--color-primary-red);
}
